import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Flushable;
import java.io.IOException;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterFlushTest {

    private CSVFormat format;
    private Appendable appendable;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        format = mock(CSVFormat.class);
    }

    @Test
    void flush_WithFlushableOut_ShouldInvokeFlush() throws IOException {
        Flushable flushableOut = mock(Flushable.class);
        // CSVPrinter constructor takes Appendable, Flushable is not Appendable so we create a mock that implements both
        Appendable appendableFlushable = mock(Appendable.class, withSettings().extraInterfaces(Flushable.class));
        doNothing().when((Flushable) appendableFlushable).flush();

        printer = new CSVPrinter(appendableFlushable, format);
        printer.flush();

        verify((Flushable) appendableFlushable, times(1)).flush();
    }

    @Test
    void flush_WithNonFlushableOut_ShouldNotThrow() throws IOException {
        appendable = mock(Appendable.class);
        printer = new CSVPrinter(appendable, format);
        // flush should do nothing and not throw
        printer.flush();
    }
}
